import { useEffect, useState } from "react";
import { socket } from "./socket";

function Room({ room, userName, role }) {
  const [answer, setAnswer] = useState("");
  const [question, setQuestion] = useState(null);
  const [scores, setScores] = useState({});
  const [timeLeft, setTimeLeft] = useState(0);

  const [timerEnabled, setTimerEnabled] = useState(false);
  const [timeLimit, setTimeLimit] = useState(10);

  useEffect(() => {
    socket.emit("join_room", {
      roomCode: room,
      role,
      name: userName,
    });

    socket.on("receive_question", setQuestion);
    socket.on("timer_update", setTimeLeft);
    socket.on("update_scores", setScores);

    socket.on("quiz_finished", (s) => {
      alert("Квиз закончен!");
      console.log(s);
    });

    return () => {
      socket.off("receive_question");
      socket.off("timer_update");
      socket.off("update_scores");
    };
  }, [room]);

  const sendAnswer = () => {
    socket.emit("submit_answer", {
      answer,
      name: userName,
    });
  };

  return (
    <div>
      <h2>Room: {room}</h2>

      {question && (
        <div>
          {question.imageUrl && <img src={question.imageUrl} width="200" />}
          <h3>{question.text}</h3>

          {question.options.map((opt, i) => (
            <button key={i} onClick={() => setAnswer(opt)}>
              {opt}
            </button>
          ))}
        </div>
      )}

      <h2>Время: {timeLeft}</h2>

      <input onChange={(e) => setAnswer(e.target.value)} />
      <button onClick={sendAnswer}>Ответить</button>

      <h3>Leaderboard</h3>
      {Object.entries(scores).map(([u, s]) => (
        <div key={u}>
          {u}: {s}
        </div>
      ))}

      {role === "organizer" && (
        <>
          <h3>Настройки</h3>

          <label>
            <input
              type="checkbox"
              onChange={(e) => setTimerEnabled(e.target.checked)}
            />
            Таймер
          </label>

          <input
            type="number"
            onChange={(e) => setTimeLimit(Number(e.target.value))}
          />

          <br />

          <button
            onClick={() =>
              socket.emit("start_quiz", {
                roomCode: room,
                quizId: 1,
                timerEnabled,
                timeLimit,
              })
            }
          >
            Старт квиза
          </button>

          <button
            onClick={() =>
              socket.emit("next_question", { roomCode: room })
            }
          >
            Следующий вопрос
          </button>
        </>
      )}
    </div>
  );
}

export default Room;
